const incoming = $('When Executed by Another Workflow').first()?.json ?? $('When clicking \'Execute workflow\'').first()?.json ?? {};
const cookieHeader = typeof incoming.cookieHeader === 'string' ? incoming.cookieHeader.trim() : '';
const userAgent = typeof incoming.userAgent === 'string' ? incoming.userAgent.trim() : '';
return [{
  json: {
    targetUrl: 'https://clubspark.lta.org.uk/AvondaleTennisClub/Admin/Contacts',
    forceRefresh: [true, 'true', '1', 1, 'yes'].includes(incoming.forceRefresh),
    cookieHeader: cookieHeader || undefined,
    userAgent: userAgent || undefined,
    authenticatedUrl: incoming.authenticatedUrl ?? undefined,
    pageTitle: incoming.pageTitle ?? undefined,
    cookieCount: incoming.cookieCount ?? undefined,
    probe: incoming.probe ?? null,
  },
}];

const item = $input.first();
const payload = item.json ?? {};
const csvText = String(payload.body ?? payload.data ?? payload.stdout ?? '').trim();
const detail = JSON.stringify(Object.keys(payload));
if (!csvText) {
  throw new Error(`ClubSpark exporter did not return CSV output. Payload keys: ${detail}`);
}
if (/^<!DOCTYPE html/i.test(csvText) || /^<html/i.test(csvText) || /<title>.*Sign in/i.test(csvText)) {
  throw new Error('ClubSpark exporter returned HTML instead of CSV. The browser login did not complete successfully.');
}
function parseCsv(text) {
  const rows = [];
  let row = [], field = '', inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i], next = text[i + 1];
    if (inQuotes) {
      if (ch === '"' && next === '"') { field += '"'; i++; }
      else if (ch === '"') { inQuotes = false; }
      else { field += ch; }
    } else {
      if (ch === '"') { inQuotes = true; }
      else if (ch === ',') { row.push(field); field = ''; }
      else if (ch === '\r' && next === '\n') { row.push(field); field = ''; rows.push(row); row = []; i++; }
      else if (ch === '\n' || ch === '\r') { row.push(field); field = ''; rows.push(row); row = []; }
      else { field += ch; }
    }
  }
  if (field || row.length) { row.push(field); rows.push(row); }
  return rows;
}
const allRows = parseCsv(csvText);
if (allRows.length < 2) throw new Error(`CSV has fewer than 2 rows (got ${allRows.length}).`);
const headers = allRows[0].map((h) => h.trim());
if (!headers.includes('First name') || !headers.includes('Last name')) {
  throw new Error(`ClubSpark export did not return the expected contacts CSV headers. Got: ${headers.slice(0, 8).join(', ')}`);
}
const dataRows = allRows.slice(1).filter((r) => r.some((c) => c.trim() !== ''));
if (!dataRows.length) {
  return [{ json: { rowCount: 0, message: 'No data rows in CSV export.' } }];
}
return dataRows.map((row) => ({ json: Object.fromEntries(headers.map((h, i) => [h, (row[i] ?? '').trim()])) }));

const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sqlInteger = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  const digits = String(value).replace(/[^0-9-]+/g, '');
  if (!digits || digits === '-') return 'NULL';
  const parsed = Number.parseInt(digits, 10);
  return Number.isNaN(parsed) ? 'NULL' : String(parsed);
};
const rows = $input.all().map((item) => item.json ?? {});
if (!rows.length) {
  throw new Error('No parsed contact rows were available to build the import SQL.');
}
const columns = [
  { db: 'Venue ID', headers: ['Venue ID'] },
  { db: 'Unique ID', headers: ['Unique ID'] },
  { db: 'First name', headers: ['First name'] },
  { db: 'Last name', headers: ['Last name'] },
  { db: 'gender', headers: ['Gender'] },
  { db: 'age', headers: ['Age'], type: 'integer' },
  { db: 'junior', headers: ['Junior'] },
  { db: 'Date of birth', headers: ['Date of birth'] },
  { db: 'Email address', headers: ['Email address'] },
  { db: 'Phone number', headers: ['Phone number'] },
  { db: 'Work number', headers: ['Work number'] },
  { db: 'Mobile number', headers: ['Mobile number'] },
  { db: 'Emergency contact name', headers: ['Emergency contact name'] },
  { db: 'Emergency phone number', headers: ['Emergency phone number'] },
  { db: 'Address 1', headers: ['Address 1'] },
  { db: 'Address 2', headers: ['Address 2'] },
  { db: 'Address 3', headers: ['Address 3'] },
  { db: 'town', headers: ['Town', 'town'] },
  { db: 'county', headers: ['County', 'county'] },
  { db: 'country', headers: ['Country', 'country'] },
  { db: 'postcode', headers: ['Postcode', 'postcode'] },
  { db: 'British Tennis Number', headers: ['British Tennis Number'], type: 'integer' },
  { db: 'Date joined venue', headers: ['Date joined venue'] },
  { db: 'Medical history', headers: ['Medical history'] },
  { db: 'occupation', headers: ['Occupation', 'occupation'] },
  { db: 'registered', headers: ['Registered', 'registered'] },
  { db: 'unsubscribed', headers: ['Unsubscribed', 'unsubscribed'] },
  { db: 'Member status', headers: ['Member status'] },
  { db: 'Last active', headers: ['Last active'] },
  { db: 'created', headers: ['Created', 'created'] },
  { db: 'Receipt of Emails', headers: ['Receipt of Emails'] },
  { db: 'Share Contact Detail', headers: ['Share Contact Detail'] },
  { db: "Member's Directory", headers: ["Member's Directory"] },
  { db: 'photography', headers: ['Photography', 'photography'] }
];
const getValue = (row, headers) => {
  for (const header of headers) {
    if (Object.prototype.hasOwnProperty.call(row, header)) {
      return row[header];
    }
  }
  return null;
};
const quotedColumns = columns.map(({ db }) => '"' + db.replace(/"/g, '""') + '"').join(', ');
const values = rows.map((row) => {
  const record = columns.map((column) => {
    const rawValue = getValue(row, column.headers);
    return column.type === 'integer' ? sqlInteger(rawValue) : sqlLiteral(rawValue);
  });
  return '(' + record.join(', ') + ')';
}).join(',\n  ');
const sql = 'BEGIN;\n' +
  'SELECT * FROM public.prepare_raw_contacts_import_staging();\n' +
  'INSERT INTO public.raw_contacts_import_staging (' + quotedColumns + ')\n' +
  'VALUES\n  ' + values + ';\n' +
  'SELECT * FROM public.reconcile_raw_contacts_from_staging();\n' +
  'COMMIT;';
return [{ json: { sql, rowCount: rows.length } }];

const counts = $input.first().json ?? {};
const session = $('Execute ClubSpark Auth Session').first().json ?? {};
return [{
  json: {
    total_contacts: Number(counts.total_contacts ?? 0),
    authenticated: session.authenticated === true,
    targetUrl: session.targetUrl ?? 'https://clubspark.lta.org.uk/AvondaleTennisClub/Admin/Contacts',
    authenticatedUrl: session.authenticatedUrl ?? null,
    pageTitle: session.pageTitle ?? null,
    userAgent: session.userAgent ?? null,
    cookieHeader: session.cookieHeader ?? null,
    cookieCount: Number(session.cookieCount ?? 0),
    probe: session.probe ?? null,
  },
}];
